const output = items[0].json.stdout;
const result = JSON.parse(output);

// Retourner chaque fichier comme un item séparé avec le chemin complet formaté
return result.files.map(file => ({
  json: {
    page_number: file.page_number,
    file_name: file.file_name,
    file_path: file.file_path,
    // Nouveau champ avec le chemin formaté pour n8n
    formatted_path: `C:/split_pdf/document_pages_facture/${file.file_name}`,
    total_pages: result.total_pages
  }
}));

return items.map(item => ({
  json: {
    model: "mistral-ocr-latest",
    document: {
      type: "document_url",
      document_url: `data:application/pdf;base64,${item.binary.data.data}`
    },
    include_image_base64: false
  },
  binary: item.binary
}));

const rawText = $input.first().json.text || 
                $input.first().json.choices?.[0]?.message?.content || '';

const code3Data = $node["Loop Over Items"].json;
const is_retry  = code3Data.is_retry || false;

let factureData = {};

// ─── Nettoyage : évaluer les expressions arithmétiques dans les valeurs JSON
function evaluerExpressionsArithmetiques(texte) {
  return texte.replace(
    /("[\w]+")\s*:\s*([\d\s\+\-\*\/\.]+)(?=[,\n\}])/g,
    (match, key, expr) => {
      try {
        if (/^[\d\s\+\-\*\/\.]+$/.test(expr.trim())) {
          const resultat = Function('"use strict"; return (' + expr.trim() + ')')();
          if (typeof resultat === 'number' && isFinite(resultat)) {
            return key + ': ' + resultat;
          }
        }
      } catch(e) {}
      return match;
    }
  );
}

// ─── Réparation JSON tronqué ─────────────────────────────────────────────
function repairerJSON(texte) {
  let t = texte.trim();
  t = t.replace(/,\s*([}\]])/g, '$1');

  let accolades = 0, crochets = 0, inString = false, escaped = false;
  for (const ch of t) {
    if (escaped)     { escaped = false; continue; }
    if (ch === '\\') { escaped = true;  continue; }
    if (ch === '"')  { inString = !inString; continue; }
    if (inString)    continue;
    if (ch === '{')  accolades++;
    if (ch === '}')  accolades--;
    if (ch === '[')  crochets++;
    if (ch === ']')  crochets--;
  }

  const lignes = t.split('\n');
  const derniereLigne = lignes[lignes.length - 1].trim();
  if (derniereLigne &&
      !derniereLigne.endsWith(',') &&
      !derniereLigne.endsWith('{') &&
      !derniereLigne.endsWith('[') &&
      !derniereLigne.endsWith('}') &&
      !derniereLigne.endsWith(']') &&
      !derniereLigne.endsWith('"')) {
    lignes.pop();
    t = lignes.join('\n');
  }
  t = t.replace(/,\s*$/, '');
  while (crochets > 0)  { t += ']'; crochets--;  }
  while (accolades > 0) { t += '}'; accolades--; }
  return t;
}

// ─── Parse robuste (4 stratégies) ────────────────────────────────────────
function parseRobuste(texte) {
  let texteNettoye = evaluerExpressionsArithmetiques(texte);
  try { return JSON.parse(texteNettoye); } catch(e) {}
  try { return JSON.parse(repairerJSON(texteNettoye)); } catch(e) {}
  try { return JSON.parse(repairerJSON(texte)); } catch(e) {
    throw new Error('Toutes les stratégies de parsing ont échoué : ' + e.message);
  }
}

// ─── Extraction du JSON brut depuis la réponse LLM ───────────────────────
try {
  const matchCodeBlock = rawText.match(/```json\s*([\s\S]*?)```/i);
  if (matchCodeBlock) {
    factureData = parseRobuste(matchCodeBlock[1].trim());
  } else {
    const matchBraces = rawText.match(/\{[\s\S]*/);
    if (matchBraces) {
      factureData = parseRobuste(matchBraces[0]);
    } else {
      throw new Error('Aucun JSON trouvé dans la réponse');
    }
  }
} catch (e) {
  factureData = {
    erreur: 'Parsing échoué : ' + e.message,
    raw:    rawText.substring(0, 500)
  };
}

// ─── Normalisation des montants (espaces résiduels → nombre) ─────────────
function toNumber(val) {
  if (typeof val === 'number') return val;
  if (typeof val === 'string') {
    const cleaned = val.replace(/\s/g, '').replace(',', '.');
    const n = parseFloat(cleaned);
    return isFinite(n) ? n : 0;
  }
  return 0;
}

// ─── Normalisation des totaux globaux ────────────────────────────────────
factureData.montant_ht    = toNumber(factureData.montant_ht);
factureData.tva_montant   = toNumber(factureData.tva_montant);
factureData.total_ttc     = toNumber(factureData.total_ttc);
factureData.montant_du    = toNumber(factureData.montant_du);
factureData.tva_taux      = toNumber(factureData.tva_taux) || 20;
factureData.total_contrat = toNumber(factureData.total_contrat);

// ─── Normalisation du tableau lignes[] unifié ─────────────────────────────
const lignesRaw = Array.isArray(factureData.lignes) ? factureData.lignes : [];

const lignes = lignesRaw.map(l => ({
  type:         l.type         || 'detail_forfait',
  numero_appel: l.numero_appel || null,
  forfait:      l.forfait      || null,
  designation:  l.designation  || '',
  date_debut:   l.date_debut   || null,
  date_fin:     l.date_fin     || null,
  taux_pct:     l.taux_pct !== undefined && l.taux_pct !== null ? toNumber(l.taux_pct) : null,
  montant_ttc:  toNumber(l.montant_ttc)
}));

// ─── Reconstruction des vues dérivées pour compatibilité pipeline ─────────
// Ces tableaux sont reconstruits depuis lignes[] — ils ne viennent plus du LLM

const frais_mensuels  = lignes.filter(l => l.type === 'frais_mensuel');
const frais_ponctuels = lignes.filter(l => l.type === 'frais_ponctuel');
const promotions      = lignes.filter(l => l.type === 'promotion');
const lignes_detail   = lignes.filter(l => l.type === 'detail_forfait');

// Regrouper les lignes de détail par numero_appel pour reconstituer lignes_par_forfait
const mapForfaits = {};
for (const l of lignes_detail) {
  const key = l.numero_appel || l.forfait || 'inconnu';
  if (!mapForfaits[key]) {
    mapForfaits[key] = {
      numero_appel:  l.numero_appel,
      forfait:       l.forfait,
      total_contrat: factureData.total_contrat, // total_contrat de la page courante
      details:       []
    };
  }
  mapForfaits[key].details.push({
    designation: l.designation,
    date_debut:  l.date_debut,
    date_fin:    l.date_fin,
    taux_pct:    l.taux_pct,
    montant_ttc: l.montant_ttc
  });
}
const lignes_par_forfait_courant = Object.values(mapForfaits);

// ─── Au retry : fusionner avec les données du 1er passage ─────────────────
let lignes_par_forfait_final = lignes_par_forfait_courant;

if (is_retry) {
  try {
    const prevData = $node["Code4"].json;

    // Conserver les champs d'en-tête depuis le 1er passage (page globale)
    const champsAConserver = [
      'numero_facture', 'date_facture', 'fournisseur_nom', 'client_code',
      'periode_debut',  'periode_fin',
      'montant_ht',     'tva_taux',     'tva_montant',
      'total_ttc',      'montant_du'
    ];
    for (const champ of champsAConserver) {
      if (prevData[champ] !== undefined && prevData[champ] !== null && prevData[champ] !== '') {
        factureData[champ] = prevData[champ];
      }
    }

    // Conserver les frais globaux si le retry ne les a pas re-extraits
    const prevLignes = Array.isArray(prevData.lignes) ? prevData.lignes : [];
    const prevFraisMensuels  = prevLignes.filter(l => l.type === 'frais_mensuel');
    const prevFraisPonctuels = prevLignes.filter(l => l.type === 'frais_ponctuel');
    const prevPromotions     = prevLignes.filter(l => l.type === 'promotion');

    if (!frais_mensuels.length  && prevFraisMensuels.length)
      lignes.unshift(...prevFraisMensuels);
    if (!frais_ponctuels.length && prevFraisPonctuels.length)
      lignes.unshift(...prevFraisPonctuels);
    if (!promotions.length      && prevPromotions.length)
      lignes.unshift(...prevPromotions);

    // Fusionner lignes_par_forfait (nouvelles pages enrichissent les anciennes)
    const forfaitsExistants = prevData.lignes_par_forfait || [];
    const mapMerge = {};
    for (const f of forfaitsExistants) {
      const key = f.numero_appel || f.forfait || JSON.stringify(f);
      mapMerge[key] = f;
    }
    for (const f of lignes_par_forfait_courant) {
      const key = f.numero_appel || f.forfait || JSON.stringify(f);
      mapMerge[key] = f; // Le nouveau écrase (plus complet)
    }
    lignes_par_forfait_final = Object.values(mapMerge);

  } catch(e) {}
}

// ─── Calcul de l'écart ────────────────────────────────────────────────────
// Page globale  : total_ttc > 0, total_contrat = 0 → écart = total_ttc - somme(total_contrat des forfaits)
// Page de détail: total_ttc = 0, total_contrat > 0  → pas d'écart à ce stade
const sommeForfaits = lignes_par_forfait_final
  .reduce((acc, f) => acc + toNumber(f.total_contrat), 0);

const ecart_montant = factureData.total_ttc
  ? Math.abs(Math.round((factureData.total_ttc - sommeForfaits) * 100) / 100)
  : 0;

// ─── Extraction et normalisation du champ page ───────────────────────────
const pageRaw    = factureData.page || `${(code3Data.page_index ?? 0) + 1}`;
const pageMatch  = String(pageRaw).match(/^(\d+)(?:\/(\d+))?$/);
const page_actuelle_num = pageMatch ? parseInt(pageMatch[1], 10) : (code3Data.page_index ?? 0) + 1;
const total_pages_num   = pageMatch?.[2] ? parseInt(pageMatch[2], 10) : (code3Data.total_pages ?? null);
const page_label        = total_pages_num ? `${page_actuelle_num}/${total_pages_num}` : `${page_actuelle_num}`;

// ─── Sortie finale ────────────────────────────────────────────────────────
return [{
  json: {
    // ── Champs d'identification ──
    page:               page_label,
    numero_facture:     factureData.numero_facture  || '',
    date_facture:       factureData.date_facture    || '',
    fournisseur_nom:    factureData.fournisseur_nom || 'Maroc Telecom',
    client_code:        factureData.client_code     || '',
    periode_debut:      factureData.periode_debut   || '',
    periode_fin:        factureData.periode_fin     || '',

    // ── Tableau unifié (nouveau format) ──
    lignes,

    // ── Vues dérivées (compatibilité avec les nodes suivants) ──
    frais_mensuels,
    frais_ponctuels,
    promotions,
    lignes_par_forfait: lignes_par_forfait_final,

    // ── Totaux globaux ──
    montant_ht:         factureData.montant_ht,
    tva_taux:           factureData.tva_taux,
    tva_montant:        factureData.tva_montant,
    total_ttc:          factureData.total_ttc,
    montant_du:         factureData.montant_du,
    total_contrat:      factureData.total_contrat,

    // ── Métadonnées pipeline ──
    ecart_montant,
    page_index:         page_actuelle_num - 1,
    is_retry,
    dff_numero:         code3Data.dff_numero  || '',
    FactureFrns:        code3Data.FactureFrns || '',
    Raison:             code3Data.Raison      || '',
    pdf_dest:           code3Data.pdf_dest    || '',

    // ── Erreur éventuelle ──
    ...(factureData.erreur ? { erreur: factureData.erreur, raw: factureData.raw } : {})
  }
}];

const items = $input.all();
const result = [];

for (const item of items) {
  // ── L'output du LLM est dans .output ou directement dans .json ──────
  const base = item.json.output || item.json;
  const lignes = base.lignes || [];

  for (const l of lignes) {
    result.push({
      json: {
        numero_facture:  base.numero_facture  || null,
        date_facture:    base.date_facture    || null,
        fournisseur_nom: base.fournisseur_nom || null,
        client_code:     base.client_code     || null,
        page_facture:    base.page            || null,
        numero_appel:    base.numero_appel      || null,
        type_ligne:      l.type              || null,    
        forfait:         l.forfait           || null,
        total_contrat:   base.total_contrat  || 0,
        designation:     l.designation       || null,
        date_debut:      l.date_debut        || null,
        date_fin:        l.date_fin          || null,
        taux_pct:        l.taux_pct          ?? null,
        // ── LLM retourne "montant" ou "montant_ttc" selon les pages ──
        montant_ttc:     l.montant_ttc ?? l.montant ?? 0,
      }
    });
  }
}

return result.length > 0 ? result : [{ json: { error: 'Aucune ligne extraite', input: $input.first().json } }];

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "page": {
      "type": "string",
      "description": "Numéro de page au format X/Y tel que détecté dans le document. Ex: '2/158'"
    },
    "numero_facture": {
      "type": "string",
      "description": "Numéro de facture Maroc Telecom. Chercher les mots-clés : 'N° Facture', 'Facture N°', 'Référence facture'. Ex: 'F2024-001234'"
    },
    "date_facture": {
      "type": "string",
      "description": "Date de la facture au format tel que détecté dans le document. Ex: '04/07/2024'"
    },
    "numero_appel": {
      "type": ["string", "null"],
      "description": "Numéro de téléphone concerné par la page. Ex: '06 62 71 16 34'."
    },
    "fournisseur_nom": {
      "type": "string",
      "description": "Nom du fournisseur émetteur de la facture. Toujours 'Maroc Telecom' ou 'IAM'"
    },
    "total_contrat": {
      "type": "number",
      "description": "Valeur du TOTAL CONTRAT de la page. Format marocain : le point '.' est séparateur de milliers, la virgule ',' est séparateur décimal. Convertir en nombre JSON standard. Ex: '1.234,56' → 1234.56. null si absent"
    },
    "lignes": {
      "type": "array",
      "description": "Toutes les lignes de facturation de la page. Obligatoire : ne jamais retourner un tableau vide si des lignes sont visibles. Extraire TOUTES les lignes sans exception",
      "items": {
        "type": "object",
        "properties": {
          "type": {
            "type": "string",
            "description": "Type de ligne selon son contexte : 'detail_forfait' si détail d'un forfait, 'frais_mensuel' si abonnement ou frais récurrent mensuel, 'frais_ponctuel' si frais exceptionnel ou unique, 'promotion' si remise ou réduction appliquée"
          },
          "forfait": {
            "type": ["string", "null"],
            "description": "Nom du forfait parent auquel appartient cette ligne. Ex: 'FORFAIT BUSINESS 100'. null si la ligne n'est pas rattachée à un forfait"
          },
          "designation": {
            "type": "string",
            "description": "Libellé exact de la ligne tel qu'affiché dans la facture, sans accents ni caractères non-ASCII (é→e, à→a, ç→c, '→espace). REGLE CRITIQUE : chaque ligne du tableau = une entrée distincte dans le tableau lignes. Ne jamais fusionner deux lignes séparées"
          },
          "date_debut": {
            "type": ["string", "null"],
            "description": "Date de début de la période de facturation de la ligne au format DD/MM/YYYY. null si absente"
          },
          "date_fin": {
            "type": ["string", "null"],
            "description": "Date de fin de la période de facturation de la ligne au format DD/MM/YYYY. null si absente"
          },
          "montant": {
            "type": "number",
            "description": "Montant TTC de la ligne. Format marocain : point '.' = séparateur milliers, virgule ',' = séparateur décimal. Convertir en nombre standard. Ex: '1.234,56' → 1234.56. Les promotions et remises sont en négatif. Ex: '-120,00' → -120.00"
          }
        },
        "required": ["type", "forfait", "designation", "date_debut", "date_fin", "montant"]
      }
    }
  },
  "required": ["page", "numero_facture", "date_facture", "fournisseur_nom", "total_contrat", "lignes"]
}
